1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const countAliveNeighbors = (
12	  [x, y]: Cell,
13	  aliveKeys: ReadonlySet<string>,
14	): number =>
15	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => aliveKeys.has(cellKey([x + dx, y + dy])))
16	    .length;
17	
18	const survives = (neighborCount: number): boolean =>
19	  neighborCount === 2 || neighborCount === 3;
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const aliveKeys = new Set(cells.map(cellKey));
23	  return cells.filter((cell) => survives(countAliveNeighbors(cell, aliveKeys)));
24	}
25

