const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const countAliveNeighbors = (
  cell: Cell,
  aliveKeys: ReadonlySet<string>,
): number =>
  neighborsOf(cell).filter((neighbor) => aliveKeys.has(cellKey(neighbor))).length;
